// ===== NY Panther 21 (16 figures) =====
foreach ([
    ['Afeni Shakur', 'Female', '1947-01-10', '2016-05-02', 'Born Alice Faye Williams in Lumberton, NC; joined Harlem BPP 1968 and became section leader. Arrested April 2, 1969 in the Panther 21 case, conducted her own legal defense while pregnant with her son Tupac. Facing 300+ years, she cross-examined witnesses and helped secure acquittal of all 13 defendants. Tupac born one month later June 16, 1971.'],
    ['Lumumba Abdul Shakur', 'Male', '1943-01-09', '1986-02-03', 'Born Anthony Coston in Atlantic City, NJ; led the Harlem chapter of the BPP and was lead defendant in the Panther 21 case. Spent two years on Rikers Island awaiting trial. After being acquitted on all 156 counts May 13, 1971, distanced himself from post-split party. Found dead in Louisiana 1986.'],
    ['Dhoruba al-Mujahid bin Wahad', 'Male', '1944-06-30', null, 'Born Richard Earl Moore in the South Bronx; joined the BPP August 1968 and rose to NY State Field Secretary. Acquitted Panther 21 May 1971; soon after went underground with the BLA. June 1971 arrested for attempted murder of two NYPD officers; wrongfully convicted 1973. Released 1990 after FBI COINTELPRO files revealed exculpatory evidence had been withheld.'],
    ['Joan Victoria Bird', 'Female', '1949-03-09', null, 'Bronx Community College nursing student when she joined the BPP in 1968. Headed the NY chapter\'s medical care program and free health clinics. Held under high bail; one of two women among the original 21 defendants.'],
    ['Robert Steele Collier', 'Male', '1936-01-01', '2010-02-12', 'Founder of the New York chapter of the BPP. Earlier had been entrapped in a 1965 government-set-up plot to bomb the Statue of Liberty. Later moved to Poughkeepsie and served as adjunct professor at Marist College.'],
    ['Curtis Powell', 'Male', '1935-01-01', '2002-12-15', 'Born in Orange, NJ; PhD in biochemistry from University of Stockholm 1968; worked at Columbia Presbyterian Medical Center. After joining the NY BPP, arrested in the Panther 21 case. Following acquittal, moved to Africa and developed a vaccine for trypanosomiasis (sleeping sickness). Returned to NY and died in Queens.'],
    ['Ali Bey Hassan', 'Male', null, null, 'Born John J. Casson; U.S. Navy veteran (enlisted 1955) who served in the Gunnery division. Joined the BPP in 1968 after hearing Bobby Seale speak. His writings appear in the collective Panther 21 autobiography "Look for Me in the Whirlwind."'],
    ['Lee Berry', 'Male', null, null, 'Vietnam War veteran being treated for epilepsy at the Manhattan VA Hospital when arrested April 2, 1969. Went without medical care for three months in custody and underwent a contested appendectomy at Bellevue. Case was severed and tried separately due to his medical condition.'],
    ['Kwando Mbiassi Kinshasa', 'Male', null, null, 'Born William King Jr. After acquittal he became a scholar of African American Studies and professor at John Jay College of Criminal Justice (CUNY).'],
    ['Lonnie Epps', 'Male', null, null, 'At 17, one of the youngest of the Panther 21 defendants; granted youthful offender status. Released on $10,000 bail; rearrested during the trial for courtroom altercation. Acquitted of original conspiracy counts May 1971.'],
    ['Lee Roper', 'Male', null, null, 'Later changed his name to Shaba Om. Acquitted with the rest of the defendants on all 156 counts.'],
    ['Michael Tabor', 'Male', '1946-12-13', '2010-10-17', 'Took the name Cetewayo after the 19th-century Zulu king. Authored the influential 1970 BPP pamphlet "Capitalism Plus Dope Equals Genocide." Jumped bail during the trial, fleeing to Algeria; acquitted in absentia. In 1972 moved to Lusaka, Zambia, where he became a popular jazz radio DJ on 5 FM.'],
    ['Jamal Joseph', 'Male', '1953-01-01', null, 'Born Edward L. Joseph in NYC; joined the BPP in September 1968 at age 15 — the youngest member of the Panther 21. In 1981 convicted of harboring a fugitive; served 5.5 years of a 12-year sentence, earning college degrees while inside. Now professor of professional practice and former chair of Columbia University\'s Graduate Film Division; author of the 2012 memoir "Panther Baby."'],
    ['Abayama Katara', 'Male', null, null, 'Born Alex McKiever; 17 at arrest April 2, 1969. Detained on Rikers Island at the Adolescent Remand Shelter; held political education classes for fellow detainees alongside Jamal Joseph.'],
    ['Baba Odinga', 'Male', null, null, 'Born Walter Johnson. Continued participating in the post-Panther political prisoner support and Pan-African organizing networks. (Not to be confused with Sekou Odinga.)'],
    ['Richard Harris', 'Male', null, null, 'Inspired to political activism after hearing Malcolm X speak at the Newark Mosque.'],
] as $row) {
    [$name, $gender, $bd, $dd, $bio] = $row;
    $parts = explode(' ', $name); $first = $parts[0]; $last = end($parts);
    $people[] = [
        'name' => $name, 'first_name' => $first, 'last_name' => $last,
        'gender' => $gender, 'race' => 'Black', 'state' => 'New York',
        'birthdate' => $bd, 'death_date' => $dd,
        'description' => $bio . ' One of the New York Panther 21; acquitted on all 156 counts on May 13, 1971.',
        'affiliation' => ['Black Panther Party', 'New York Panther 21'],
        'ideologies' => ['Black liberation', 'Revolutionary socialism'],
        'cases' => [['institution' => $ny21Inst, 'arrest_date' => '1969-04-02', 'sentenced_date' => '1971-05-13', 'release_date' => '1971-05-13', 'sentence' => 'Acquitted on all 156 counts.', 'convicted' => 'No — acquitted', 'judge' => 'Hon. John M. Murtagh', 'prosecutor' => 'Joseph A. Phillips (ADA Manhattan)', 'charges' => $ny21Charges]],
    ];
}

// ===== New Haven Panther + Soledad/SQ6 + Angela Davis + Geronimo Pratt =====
