$nhSqsl = [];
foreach ([
    ['Bobby George Seale', 'Male', '1936-10-22', null, 'California', 'Co-founded the Black Panther Party with Huey P. Newton in Oakland October 1966 and served as Chairman. As Chicago Eight defendant, bound and gagged in court by Judge Julius Hoffman. Indicted in the New Haven case; jury deadlocked 11-1 for acquittal; charges dismissed May 25, 1971.', ['Black Panther Party (co-founder, Chairman)'], 'New Haven Panther trial', '1970-08-15', '1971-05-25', 'New Haven charges dismissed (jury 11-1 for acquittal); separately served 4 years contempt for Chicago 8 trial.'],
    ['Ericka Huggins', 'Female', '1948-01-05', null, 'Connecticut', 'Born Ericka Jenkins in Washington DC; widow of John Huggins (assassinated UCLA campus Jan 17, 1969). Founded New Haven BPP chapter 1969. Held with her infant daughter for two years on Niantic Prison; charges dismissed May 25, 1971 (jury 10-2 for acquittal). Later directed Oakland Community School (1973-1981).', ['Black Panther Party'], 'New Haven Panther trial', '1969-05-22', '1971-05-25', 'Charges dismissed after hung jury.'],
    ['Lonnie McLucas', 'Male', '1945-01-01', '2016-12-15', 'Connecticut', 'Bridgeport BPP member who admitted firing the chest shot that killed Alex Rackley but refused to plead guilty in exchange for testimony. The first of the New Haven trials began May 1970 and ended September 1, 1970 with conviction on the lesser charge of conspiracy to commit murder; sentenced 12-15 years.', ['Black Panther Party (Bridgeport)'], 'New Haven Panther trial', '1969-05-21', '1974-12-15', '12-15 years (conviction on conspiracy only); released on appeal bond 1974.'],
    ['Warren Aloysious Kimbro', 'Male', '1934-04-29', '2009-02-03', 'Connecticut', 'New Haven BPP member who fired the first shot into Alex Rackley\'s head in Middlefield, CT May 21, 1969. Pleaded guilty to second-degree murder and turned state\'s evidence; sentenced to mandatory life term, paroled after four years. After release attended Harvard\'s Graduate School of Education and led Project MORE for over 20 years.', ['Black Panther Party'], 'New Haven Panther trial', '1969-05-22', '1974-06-15', 'Life sentence; served 4 years.'],
] as $row) {
    [$name, $gender, $bd, $dd, $state, $bio, $affiliation, $caseInst, $arrest, $release, $sentence] = $row;
    $parts = explode(' ', $name); $first = $parts[0]; $last = end($parts); $middle = count($parts) >= 3 ? $parts[1] : null;
    $people[] = [
        'name' => $name, 'first_name' => $first, 'middle_name' => $middle, 'last_name' => $last,
        'gender' => $gender, 'race' => 'Black', 'state' => $state,
        'birthdate' => $bd, 'death_date' => $dd, 'description' => $bio,
        'affiliation' => $affiliation, 'ideologies' => ['Black liberation', 'Revolutionary socialism'],
        'cases' => [['institution' => $nhInst, 'arrest_date' => $arrest, 'release_date' => $release, 'sentence' => $sentence, 'convicted' => str_contains($sentence, 'dismissed') || str_contains($sentence, 'acquittal') ? 'Charges dismissed' : 'Yes', 'judge' => 'Hon. Harold M. Mulvey', 'prosecutor' => 'Arnold Markle (CT State\'s Attorney)', 'charges' => $nhCharges]],
    ];
}

// ===== Soledad Brothers / San Quentin Six =====
foreach ([
    ['George Lester Jackson', 'Male', '1941-09-23', '1971-08-21', 'California', 'Sentenced at age 18 to one-year-to-life for stealing $71 from a gas station; spent the rest of his life imprisoned, ten years in solitary. Became a BPP Field Marshal and co-founded the Black Guerrilla Family. Indicted Feb 1970 with Drumgo and Clutchette for murder of guard John V. Mills (the Soledad Brothers case). His 1970 prison-letters book "Soledad Brother" became an international bestseller. Killed by San Quentin guards August 21, 1971; his death helped trigger the Attica uprising three weeks later.', ['Black Panther Party (Field Marshal)', 'Black Guerrilla Family (founder)'], '1960-12-15', '1971-08-21', 'Held pending trial when killed', false, 'death_in_custody'],
    ['Fleeta Drumgo', 'Male', '1945-05-31', '1979-11-24', 'California', 'One of the three Soledad Brothers charged with the January 16, 1970 murder of correctional officer John V. Mills. After George Jackson\'s death, tried with Clutchette in 1972; acquitted March 27, 1972 by a San Francisco jury. Then charged as one of the San Quentin Six; acquitted again August 12, 1976. Shot to death in Oakland November 24, 1979 by unknown assailants.', ['Black Guerrilla Family', 'Soledad Brothers'], '1970-02-14', '1976-08-12', 'Acquitted in both Soledad Brothers and San Quentin Six trials.', true, null],
    ['John Wesley Clutchette', 'Male', '1944-01-01', null, 'California', 'Third Soledad Brother charged with the January 16, 1970 killing of guard John V. Mills at Soledad State Prison. The Soledad Brothers Defense Committee (which included Angela Davis) organized worldwide solidarity. Acquitted by a San Francisco jury March 27, 1972 after three days of deliberation; granted parole November 13, 1972.', ['Soledad Brothers'], '1970-02-14', '1972-11-13', 'Acquitted; paroled Nov 13, 1972.', true, null],
    ['Hugo Antonio Pinell', 'Male', '1944-03-10', '2015-08-12', 'California', 'Born in Nicaragua; brought to California age 12. Pleaded guilty to a 1964 rape charge expecting parole in six months but received a 3-years-to-life sentence; became a key prison organizer alongside George Jackson. Charged as one of the San Quentin Six for the August 21, 1971 incident; convicted in 1976 of two counts of felony assault on a guard for cutting throats of two officers (both survived) and held in solitary confinement for 43 years. Killed in a prison riot August 12, 2015.', ['Black Guerrilla Family'], '1971-08-21', null, 'Life; killed in custody by Aryan Brotherhood-associated inmates.', false, 'death_in_custody'],
    ['Johnny Larry Spain', 'Male', '1949-09-30', null, 'California', 'Born Larry Michael Armstrong in Jackson, Mississippi to white mother and Black father; sent at age six to be raised by Black foster family in LA. Imprisoned at 17 for a fatal robbery; became a follower of George Jackson and the only San Quentin Six defendant convicted of murder August 12, 1976 — for the deaths of guards Frank DeLeon and Jere P. Graham. Conviction overturned by federal Judge Thelton Henderson because Spain had been shackled in 25-pound chains throughout trial. Paroled 1988 after 21 years incarceration.', ['Black Panther Party', 'Black Guerrilla Family'], '1971-08-21', '1988-12-15', 'Two life terms (overturned on appeal); paroled 1988.', true, null],
    ['Stephen Mitchell Bingham', 'Male', '1942-01-01', null, 'California', 'Civil rights attorney accused of smuggling a 9mm Astra pistol concealed in a tape recorder to George Jackson on August 21, 1971. Fled the United States, living underground in Eastern Europe and France for 13 years. With assistance from former Attorney General Ramsey Clark, surrendered in 1984. Tried in Marin County Superior Court 1986; found not guilty of conspiracy and murder on the jury\'s first ballot.', ['Movement attorney; allied with BPP/BGF defense'], '1984-12-15', '1986-12-15', 'Acquitted on first ballot.', true, null],
    ['Willie Tate', 'Male', '1944-01-01', null, 'California', 'Born in Selma, Alabama; raised in El Paso and Fresno. Charged as one of the San Quentin Six. After the 16-month longest-in-California-history trial, acquitted of all charges August 12, 1976; paroled 1976.', ['Black Guerrilla Family'], '1971-08-21', '1976-12-15', 'Acquitted on all counts.', true, null],
    ['David Johnson', 'Male', null, null, 'California', 'One of the six prisoners charged in the August 21, 1971 San Quentin Adjustment Center incident. After the longest trial in California history, convicted August 12, 1976 of one count of felony assault on a guard, drawing additional concurrent life sentence. Released on parole 1993.', ['Black Guerrilla Family'], '1971-08-21', '1993-12-15', 'Life sentence concurrent (one count assault).', true, null],
    ['Luis Talamantez', 'Male', null, null, 'California', 'One of the six men charged in the August 21, 1971 San Quentin uprising. After the 16-month trial, acquitted on all charges August 12, 1976; paroled. Went on to become a key organizer against control-unit prisons in California.', ['Black Guerrilla Family'], '1971-08-21', '1976-12-15', 'Acquitted on all counts.', true, null],
    ['Jonathan Peter Jackson', 'Male', '1953-06-23', '1970-08-07', 'California', '17-year-old younger brother of George Jackson. On August 7, 1970 carried a satchel of three firearms (registered to Angela Davis) into the Marin County Hall of Justice during the trial of San Quentin inmate James McClain. Took Judge Harold Haley, prosecutor Gary Thomas, and three jurors hostage demanding release of the Soledad Brothers. Killed in the ensuing shootout along with Judge Haley, James McClain, and William Christmas. Triggered the federal kidnapping/murder/conspiracy charges against Angela Davis.', ['Soledad Brothers Defense Committee'], null, '1970-08-07', 'Killed during incident.', false, 'death_in_custody'],
] as $row) {
    [$name, $gender, $bd, $dd, $state, $bio, $affiliation, $arrest, $release, $sentence, $released, $deathFlag] = $row;
    $parts = explode(' ', $name); $first = $parts[0]; $last = end($parts); $middle = count($parts) >= 3 ? $parts[1] : null;
    $caseFields = ['institution' => $soledadInst, 'arrest_date' => $arrest, 'release_date' => $release, 'sentence' => $sentence, 'convicted' => str_contains($sentence, 'cquitted') ? 'No — acquitted' : (str_contains($sentence, 'killed') ? 'Killed before verdict' : 'Yes'), 'charges' => 'Soledad Brothers / San Quentin Six prosecutions: murder of correctional officers, conspiracy, assault.'];
    if ($deathFlag === 'death_in_custody') $caseFields['death_in_custody_date'] = $dd;
    $isBlack = $name === 'Stephen Mitchell Bingham' ? 'White' : ($name === 'Hugo Antonio Pinell' ? 'Latino/Hispanic' : ($name === 'Luis Talamantez' ? 'Latino/Hispanic' : 'Black'));
    $people[] = [
        'name' => $name, 'first_name' => $first, 'middle_name' => $middle, 'last_name' => $last,
        'gender' => $gender, 'race' => $isBlack, 'state' => $state,
        'birthdate' => $bd, 'death_date' => $dd, 'released' => $released, 'description' => $bio,
        'affiliation' => $affiliation, 'ideologies' => ['Black liberation', 'Revolutionary socialism', 'Prisoner liberation'],
        'cases' => [$caseFields],
    ];
}

// Angela Davis + Geronimo Pratt + Frank "Big Black" Smith
$people[] = ['name' => 'Angela Yvonne Davis', 'first_name' => 'Angela', 'middle_name' => 'Yvonne', 'last_name' => 'Davis', 'gender' => 'Female', 'race' => 'Black', 'state' => 'California', 'birthdate' => '1944-01-26', 'description' => 'Born in Birmingham, Alabama\'s "Dynamite Hill" neighborhood; UCLA philosophy professor twice fired by UC Regents at Governor Ronald Reagan\'s direction over her Communist Party membership. After Jonathan Jackson\'s August 7, 1970 raid on the Marin County Civic Center used firearms registered in her name, she went underground. Placed on the FBI Ten Most Wanted Fugitives list (the third woman ever); arrested at a Manhattan motel October 13, 1970. After 16 months in jail and a 13-week trial, acquitted by an all-white-and-Latino jury June 4, 1972 in San Jose.', 'affiliation' => ['Communist Party USA', 'Black Panther Party (allied)', 'Soledad Brothers Defense Committee', 'Che-Lumumba Club'], 'ideologies' => ['Marxism', 'Black feminism', 'Communism', 'Prison abolition'], 'cases' => [['institution' => ['name' => 'Santa Clara County Superior Court — People v. Davis', 'city' => 'San Jose', 'state' => 'California'], 'arrest_date' => '1970-10-13', 'release_date' => '1972-06-04', 'sentence' => 'Acquitted on all counts June 4, 1972.', 'convicted' => 'No — acquitted', 'judge' => 'Hon. Richard E. Arnason', 'prosecutor' => 'Albert Harris', 'charges' => 'California state: murder, kidnapping, conspiracy (related to August 7, 1970 Marin County Civic Center hostage-taking by Jonathan Jackson; Judge Harold Haley killed; firearms registered in Davis\'s name).']]];

$people[] = ['name' => 'Elmer Gerard Pratt', 'first_name' => 'Elmer', 'middle_name' => 'Gerard', 'last_name' => 'Pratt', 'aka' => 'Geronimo Pratt; Geronimo ji-Jaga', 'gender' => 'Male', 'race' => 'Black', 'state' => 'California', 'birthdate' => '1947-09-13', 'death_date' => '2011-06-02', 'description' => 'Born in Morgan City, Louisiana; decorated two-tour Vietnam War paratrooper (82nd Airborne; Purple Heart, Silver Star). Enrolled at UCLA 1968 where Alprentice "Bunchy" Carter recruited him into the BPP. Became Deputy Minister of Defense of the LA chapter after the December 1969 LAPD assault on Panther HQ. Targeted by FBI COINTELPRO; convicted 1972 for the December 18, 1968 Santa Monica tennis-court murder of teacher Caroline Olsen. Served 27 years (8 in solitary), maintaining FBI wiretaps proved he was 400 miles away in Oakland that day. June 10, 1997 Judge Everett Dickey vacated his conviction after finding the prosecution\'s key witness Julius Butler was an undisclosed paid informant. Died in Tanzania 2011.', 'affiliation' => ['Black Panther Party (Deputy Minister of Defense, LA chapter)'], 'ideologies' => ['Black revolutionary', 'Anti-imperialism'], 'cases' => [['institution' => ['name' => 'Orange County Superior Court — Pratt habeas vacatur', 'city' => 'Santa Ana', 'state' => 'California'], 'arrest_date' => '1970-12-08', 'sentenced_date' => '1972-07-15', 'release_date' => '1997-06-10', 'sentence' => 'Life imprisonment (vacated June 10, 1997).', 'convicted' => 'Yes; vacated 1997', 'judge' => 'Hon. Kathleen Parker (1972 trial); Hon. Everett W. Dickey (1997 vacatur)', 'prosecutor' => 'Richard Kalustian (1972)', 'charges' => 'Murder, robbery, kidnapping (Santa Monica tennis-court murder of Caroline Olsen, December 18, 1968).']]];

$people[] = ['name' => 'Frank "Big Black" Smith', 'first_name' => 'Frank', 'last_name' => 'Smith', 'aka' => 'Big Black', 'gender' => 'Male', 'race' => 'Black', 'state' => 'New York', 'birthdate' => '1933-09-11', 'death_date' => '2004-07-29', 'description' => 'Born to cotton farmers in Bennettsville, SC; raised in Brooklyn. Serving 10-15 years at Attica for robbing an after-hours dice game when the September 1971 uprising broke out. As prison football coach, elected by acclamation to lead D-Yard security for both inmates and civilian observers. After the state retook the prison, singled out for prolonged torture: forced to lie naked on a table holding a football for hours under threat of castration. Paroled 1973 after 8.5 years; became leader of the Attica Defense Committee and lead plaintiff in the prisoner reparations lawsuit, which won a $12 million settlement in 2000.', 'affiliation' => ['Attica Brothers', 'Attica Defense Committee'], 'ideologies' => ['Prisoner rights', 'Black liberation'], 'cases' => [['institution' => ['name' => 'Attica Correctional Facility — Attica Brothers prisoner uprising 1971', 'city' => 'Attica', 'state' => 'New York'], 'arrest_date' => '1965-06-15', 'release_date' => '1973-12-15', 'sentence' => '10-15 years (original robbery); paroled 1973; no successful state charge from uprising.', 'convicted' => 'Yes (original robbery); no charge stemming from uprising stuck', 'charges' => 'Robbery (original); state filed no successful charge from uprising — Smith led D-Yard security and was severely tortured by guards during state retaking.']]];

// ===== AIM / Wounded Knee 1973 =====
foreach ([
    ['Carter Augustus Camp', 'Ponca', 'Oklahoma', '1941-08-18', '2013-12-27', 'Ponca AIM leader from Pawnee, Oklahoma; Haskell Institute graduate; U.S. Army veteran (Berlin 1960-63). One of the primary organizers of the 1973 Wounded Knee occupation alongside Russell Means and Dennis Banks; led the first group of AIM members who seized the trading post. Elected national chair of AIM 1973. Pleaded guilty to one count and served 3 years federal prison.', '1973-04-15', '1976-12-15', '3 years federal prison (pleaded guilty to one count).'],
    ['Clyde Howard Bellecourt', 'Ojibwe', 'Minnesota', '1936-05-08', '2022-01-11', 'Co-founder and first chairman of AIM, born on White Earth Reservation in Minnesota. Helped organize AIM Patrol, Heart of the Earth Survival School, and 1972 Trail of Broken Treaties. Indicted on federal charges related to the Wounded Knee occupation; charges dismissed/dropped. Last surviving co-founder at his 2022 death.', '1973-04-15', '1974-12-15', 'Charges dismissed/dropped.'],
    ['Vernon Franklin Bellecourt', 'Ojibwe', 'Minnesota', '1931-10-17', '2007-10-13', 'Older brother of AIM co-founder Clyde Bellecourt; emerged as AIM\'s national director and chief international spokesperson. Briefly present at Wounded Knee 1973; served principally as occupation\'s outside fundraiser and press liaison. Indicted for related federal offenses. Led AIM\'s international diplomacy with Sandinista Nicaragua, Libya, and the PLO; headed National Coalition on Racism in Sports and Media.', '1973-04-15', '1974-12-15', 'Charges dismissed/dropped.'],
    ['Stanley Robert Holder', 'Wichita', 'Oklahoma', null, null, 'Wichita Vietnam War veteran; head of security and warrior society commander during the 1973 Wounded Knee occupation; senior AIM organizer in Oklahoma and Texas. Indicted along with the rest of the Wounded Knee leadership on multiple federal felonies. Prosecution affected by the September 1974 dismissals; later participated in BIA building takeover prosecutions and the 1978 Longest Walk.', '1973-04-15', '1974-12-15', 'Charges dismissed/reduced.'],
    ['Pedro Aloysius Bissonette', 'Oglala Lakota', 'South Dakota', '1944-04-20', '1973-10-17', 'Co-founder of the Oglala Sioux Civil Rights Organization (OSCRO) and the principal Pine Ridge organizer who invited AIM onto the reservation in February 1973 to confront tribal chairman Dick Wilson. Key leader inside Wounded Knee. Arrested August 1973; offered probation in exchange for cooperative testimony against Banks and Means; threatened with 99 years if he refused. Refused. October 17, 1973 BIA police shotgunned him to death at point-blank range on Pine Ridge — AIM and family witnesses called it an assassination to silence the defense\'s key witness.', '1973-08-27', null, 'Killed by BIA police October 17, 1973 before trial.'],
    ['Anna Mae Pictou Aquash', 'Mi\'kmaq', 'South Dakota', '1945-03-27', '1975-12-12', 'Born near Shubenacadie, Nova Scotia; one of AIM\'s most prominent women organizers. Participated in the 1972 Trail of Broken Treaties and 1973 Wounded Knee occupation; worked in AIM\'s St. Paul office in early 1974 and led AIM\'s Los Angeles office later that year. Suspected by some AIM members of being an FBI informant (which she denied); kidnapped and murdered execution-style on Pine Ridge December 1975; body found February 24, 1976. Arlo Looking Cloud (2003) and John Graham (2010) later convicted of her murder.', '1973-04-15', null, 'Murdered execution-style December 1975 on Pine Ridge.'],
    ['Madonna Thunder Hawk', 'Lakota', 'South Dakota', null, null, 'Joined AIM in 1968. Participated in Alcatraz, BIA HQ, Custer Courthouse, and Wounded Knee occupations. During the 71-day Wounded Knee siege served as a medic and was a member of the "Pie Patrol" alongside Lorelei DeCora Means, Thelma Rios, Theda Nelson Clarke, and Mary Crow Dog. In 1974 co-founded Women of All Red Nations (WARN) and the Black Hills Alliance.', '1973-04-15', '1974-12-15', 'Charges dismissed/dropped.'],
    ['Phyllis Young', 'Lakota', 'South Dakota', '1949-02-24', null, 'Born on the Standing Rock Reservation; central role in AIM and as a founding member of Women of All Red Nations (WARN) in 1974. WARN\'s signature campaign exposed the forced sterilization of 3,406 American Indian women between 1973-1976. Helped coordinate the first UN conference on Indians of the Americas in Geneva (1977); led the 2016-17 anti-Dakota Access Pipeline struggle.', '1973-04-15', '1974-12-15', 'Charges dismissed/dropped.'],
    ['William Means', 'Oglala Lakota', 'South Dakota', null, null, 'Twin brother of Ted Means and younger brother of Russell Means. Participated in the Wounded Knee 1973 occupation. In 1974 co-founded the International Indian Treaty Council (IITC), AIM\'s UN-recognized international diplomatic arm; has led IITC for decades.', '1973-04-15', '1974-12-15', 'Charges dismissed/dropped.'],
    ['Severt Young Bear', 'Oglala Lakota', 'South Dakota', '1934-01-01', '1993-12-15', 'Of Porcupine District, Pine Ridge Reservation; descendant of chiefs and Wounded Knee 1890 survivors who supported AIM during Wounded Knee II. Founder and lead singer of the Porcupine Singers; credited with composing/popularizing the AIM Song. Music/dance consultant for "Dances with Wolves" and "Thunderheart."', '1973-04-15', '1974-12-15', 'Charges dismissed/dropped.'],
    ['Sarah Bad Heart Bull', 'Oglala Lakota', 'South Dakota', '1929-01-01', '2013-02-18', 'Mother of Wesley Bad Heart Bull who was stabbed to death January 21, 1973 by Darrell Schmitz in Buffalo Gap, SD. The prosecutor\'s decision to charge Schmitz only with second-degree manslaughter prompted her to ask AIM to organize a rally at the Custer County courthouse February 6, 1973. When police struck her in the face with a baton on the courthouse steps, the riot began. Convicted of inciting a riot; received indeterminate 1-5 year sentence; served 5 months. Her son\'s killer served no prison time.', '1973-02-06', '1973-07-15', '1-5 year indeterminate (fixed at 1 year); served 5 months.'],
    ['Robert Eugene Robideau', 'Ojibwe', 'Oregon', '1946-11-11', '2009-02-17', 'Born in Portland, Oregon; Leonard Peltier\'s cousin. Held degrees from Portland State and the Institute of American Indian Arts. Present at the June 26, 1975 Jumping Bull Compound shootout. September 10, 1975 ammunition exploded in Peltier\'s station wagon on the Kansas Turnpike, seriously injuring Robideau and exposing Agent Coler\'s revolver. Tried with Darrelle Butler in Cedar Rapids 1976; both acquitted on self-defense grounds. Died in Barcelona 2009 from complications of shrapnel.', '1975-09-15', '1976-09-15', 'Acquitted (Cedar Rapids 1976).'],
    ['Darrelle Dean Butler', 'Native American', 'South Dakota', null, null, 'AIM member present at the Jumping Bull Compound on June 26, 1975, when FBI agents Coler and Williams and AIM\'s Joe Stuntz were killed. Charged November 17, 1975 with two counts of first-degree murder; tried jointly with Bob Robideau in U.S. District Court Cedar Rapids, Iowa. Acquitted summer 1976 after their defense argued the agents\' approach in unmarked cars amid Pine Ridge\'s GOON-squad violence justified self-defense.', '1975-11-17', '1976-09-15', 'Acquitted (Cedar Rapids 1976).'],
    ['Joseph Killsright Stuntz Sr.', 'Coeur d\'Alene', 'Idaho', '1951-10-22', '1975-06-26', 'Born Joseph George on the Lapwai Reservation in Idaho; at age seven placed in a federal Indian boarding school in Indiana and later adopted by a white couple named Stuntz. AIM member at the Jumping Bull Compound on Pine Ridge June 26, 1975. Killed by a long-range shot through the head — presumably by an FBI sniper — body found wearing an FBI jacket from Agent Coler\'s trunk. His death was never investigated.', null, null, 'Killed before charges; the FBI never investigated his death.'],
    ['James Theodore Eagle', 'Oglala Lakota', 'South Dakota', null, null, 'AIM-affiliated Oglala Lakota teenager whose alleged theft of cowboy boots became the pretext for FBI Agents Coler and Williams to enter the Jumping Bull Compound June 26, 1975. Charged November 17, 1975 with two counts of first-degree murder along with Peltier, Robideau, and Butler. Charges voluntarily dismissed when prosecutors admitted he had not been on the reservation that day; FBI memo stated charges were dropped to focus prosecution on Peltier.', '1975-11-17', '1976-12-15', 'Charges dismissed.'],
    ['Paul Skyhorse Durant', 'Native American', 'California', null, null, 'AIM organizer arrested with Richard Mohawk Billings for the October 10, 1974 murder of Los Angeles taxi driver George Aird at the Box Canyon AIM campsite. Spent about four years incarcerated awaiting trial. Acquitted May 24, 1978 after defense established that the campsite had been set up by FBI/COINTELPRO informant Douglas Durham and that informant Virginia Blue Dove De Luce had lured them to the site as part of an effort to discredit AIM.', '1974-10-15', '1978-05-24', 'Acquitted May 24, 1978 after ~4 years pretrial detention.'],
    ['Richard Mohawk Billings', 'Native American', 'California', null, null, 'AIM organizer arrested with Paul Skyhorse Durant for the October 10, 1974 murder of taxi driver George Aird in Los Angeles. Held about four years awaiting trial; acquitted May 24, 1978 by a Los Angeles jury that accepted the defense argument that COINTELPRO informants had set up the Box Canyon campsite and framed both men.', '1974-10-15', '1978-05-24', 'Acquitted May 24, 1978 after ~4 years pretrial detention.'],
    ['Richard Oakes', 'Mohawk', 'California', '1942-05-22', '1972-09-20', 'Born at the Akwesasne Mohawk Reservation; left school at 16 for ironworking; attended San Francisco State University where he helped create one of the first American Indian Studies programs. With LaNada Boyer led the November 20, 1969 occupation of Alcatraz Island by Indians of All Tribes, lasting 19 months. Left the island after his stepdaughter Yvonne died in a fall January 5, 1970. Unarmed when shot and killed September 20, 1972 in Sonoma County; his killer was acquitted of voluntary manslaughter on a self-defense claim.', '1969-11-20', null, 'Killed September 20, 1972; killer acquitted.'],
    ['LaNada Vernae War Jack', 'Shoshone-Bannock', 'Idaho', '1947-01-01', null, 'Born on Fort Hall Indian Reservation; one of the first Native students admitted to UC Berkeley 1968. Founded Native American Student Organization; leader of the 1969 Third World Strike. Co-led the 19-month Alcatraz Occupation (Nov 1969 - June 1971) with Richard Oakes. PhD Idaho State 1999; Distinguished Professor at Boise State teaching federal Indian law.', '1969-11-20', '1971-06-15', 'Trespass / conspiracy at Alcatraz.'],
    ['John Trudell', 'Santee Dakota', 'Nevada', '1946-02-15', '2015-12-08', 'Santee Dakota; broadcast voice of Radio Free Alcatraz during the 1969-71 occupation. AIM\'s National Chairman from 1973 to 1979. February 11, 1979 burned an American flag during a demonstration at FBI headquarters in Washington DC. Less than 12 hours later, his pregnant wife Tina Manning, their three children, and his mother-in-law died in a fire at their home on the Duck Valley Reservation in Nevada. BIA police ruled it accidental; Trudell believed it was arson. Became a poet, musician, and actor before his death from cancer 2015. His FBI file ran to 17,000 pages.', '1969-11-20', '1971-06-15', 'Various AIM-related federal charges.'],
    ['Leonard Crow Dog', 'Sicangu Lakota', 'South Dakota', '1942-08-18', '2021-06-06', 'Sicangu Lakota medicine man from Rosebud Reservation; AIM\'s principal spiritual leader during the 1972 Trail of Broken Treaties and 1973 Wounded Knee occupation. Revived the banned Ghost Dance and hosted intertribal Sun Dances at Crow Dog\'s Paradise. Convicted at three subsequent trials with sentences totaling 23 years. September 1975, 185 FBI/marshals/SWAT raided his property looking for Leonard Peltier and arrested him; held in solitary at Leavenworth.', '1973-04-15', '1977-12-15', 'Suspended sentence (Wounded Knee); 23 years total across 3 trials.'],
    ['Mary Brave Bird', 'Sicangu Lakota', 'South Dakota', '1954-09-26', '2013-02-14', 'Sicangu Lakota writer and activist who joined AIM at age 18. Participated in 1972 Trail of Broken Treaties and 1973 Wounded Knee occupation, where, eight months pregnant, she gave birth to her son Pedro during a firefight. Married Leonard Crow Dog. Memoirs "Lakota Woman" (1990) and "Ohitika Woman" (1993) are foundational AIM-era texts.', '1973-04-15', '1974-12-15', 'Multiple AIM arrests.'],
] as $row) {
    [$name, $tribe, $state, $bd, $dd, $bio, $arrest, $release, $sentence] = $row;
    $parts = explode(' ', $name); $first = $parts[0]; $last = end($parts); $middle = count($parts) >= 3 ? $parts[1] : null;
    $convicted = str_contains($sentence ?? '', 'cquitted') || str_contains($sentence ?? '', 'dismissed') ? 'No — charges dismissed/acquitted' : (str_contains($sentence ?? '', 'illed') ? 'Killed before trial' : 'Yes');
    $caseFields = ['institution' => $wkInst, 'arrest_date' => $arrest, 'release_date' => $release, 'sentence' => $sentence, 'convicted' => $convicted, 'judge' => 'Hon. Fred J. Nichol (D. Minn., for Wounded Knee Leadership Trial)', 'prosecutor' => 'R. D. Hurd (federal)', 'charges' => $wkCharges];
    if (str_contains($sentence ?? '', 'illed') || $name === 'Pedro Aloysius Bissonette' || $name === 'Anna Mae Pictou Aquash' || $name === 'Joseph Killsright Stuntz Sr.' || $name === 'Richard Oakes') {
        $caseFields['death_in_custody_date'] = $dd;
    }
    $people[] = [
        'name' => $name, 'first_name' => $first, 'middle_name' => $middle, 'last_name' => $last,
        'gender' => str_contains($name, 'Mary Brave') || str_contains($name, 'Madonna') || str_contains($name, 'Phyllis') || str_contains($name, 'Sarah') || str_contains($name, 'LaNada') || str_contains($name, 'Anna Mae') ? 'Female' : 'Male',
        'race' => 'Native American', 'state' => $state,
        'birthdate' => $bd, 'death_date' => $dd,
        'released' => ! str_contains($sentence ?? '', 'illed'),
        'description' => $bio,
        'affiliation' => str_contains($name, 'Bissonette') ? ['Oglala Sioux Civil Rights Organization (OSCRO)', 'AIM supporter'] : (str_contains($name, 'Oakes') || str_contains($name, 'War Jack') ? ['Indians of All Tribes (Alcatraz Occupation)'] : ['American Indian Movement (AIM)']),
        'ideologies' => ['Indigenous sovereignty', 'Treaty rights', 'Red Power'],
        'cases' => [$caseFields],
    ];
}

// ===== Apply =====
foreach ($people as $p) {
    $p['era'] = $p['era'] ?? '1970s';
    [$prisoner, $created] = addP($p);
    echo ($created ? '  CREATED' : '  EXISTS ') . " {$p['name']} (id={$prisoner->id})\n";
    $created ? $tot['created']++ : $tot['existed']++;
    foreach ($p['cases'] ?? [] as $c) {
        if (attachC($prisoner, $c)) { echo "    + case ({$c['arrest_date']})\n"; $tot['cases']++; }
    }
}

echo "\nDone.\n";
echo "  prisoners created:        {$tot['created']}\n";
echo "  prisoners already existed: {$tot['existed']}\n";
echo "  cases added:              {$tot['cases']}\n";
